const faqs = [
  {
    title: "Core Platform & Capabilities",
    questions: [
      { q: "What is Nexgn?", a: "Nexgn is a next-generation digital signature and document infrastructure platform. Originating in New Mexico and built for the global enterprise, we provide a frictionless, highly secure environment to send, sign, and manage legally binding agreements." },
      { q: "Who is Nexgn built for?", a: "Nexgn is designed for enterprises, legal teams, financial institutions, and any organization that needs a secure, auditable, and compliant workflow for document signing at scale." },
      { q: "Which file formats are supported?", a: "Nexgn supports PDF, DOCX, XLSX, PPTX, and image formats (PNG, JPEG). All documents are converted to a standardized format for consistent rendering across devices." },
      { q: "Is Nexgn optimized for mobile devices?", a: "Yes. Nexgn's signing experience is fully responsive and optimized for mobile browsers. Native iOS and Android apps are also available for on-the-go workflows." },
      { q: "Can I save documents as reusable templates?", a: "Absolutely. You can save any document as a reusable template, pre-placing signature fields and data fields so future sends require just a few clicks." },
      { q: "Can I send a document to multiple signers at once?", a: "Yes. Nexgn supports sequential and parallel signing workflows, so you can define the exact order in which signers receive and complete the document." },
      { q: 'What is "Bulk Send" and how does it work?', a: "Bulk Send lets you upload a CSV of recipients and send a personalized version of a document to each one simultaneously — ideal for NDAs, onboarding forms, and policy acknowledgements." },
    ],
  },
  {
    title: "The Signer Experience",
    questions: [
      { q: "Do signers need a Nexgn account?", a: "No. Recipients can sign documents directly from their email without creating an account, making the experience frictionless for external parties." },
      { q: "How do signers verify their identity?", a: "Nexgn offers email-based verification, SMS OTP, knowledge-based authentication (KBA), and ID document verification depending on the compliance level required." },
      { q: "Can signers decline or reassign a document?", a: "Yes. Signers can decline with a reason or reassign to another authorized party. Senders are notified immediately in either case." },
    ],
  },
  {
    title: "Advanced Security & Legal Compliance",
    questions: [
      { q: "Are Nexgn signatures legally binding?", a: "Yes. Nexgn signatures comply with eIDAS (EU), ESIGN & UETA (US), and other international e-signature laws, making them legally enforceable in 180+ countries." },
      { q: "How is data encrypted?", a: "All data is encrypted in transit (TLS 1.3) and at rest (AES-256). Each document is stored with a unique key and a tamper-evident audit trail." },
    ],
  },
  {
    title: "Account Management & Billing",
    questions: [
      { q: "What plans does Nexgn offer?", a: "Nexgn offers Starter, Professional, and Enterprise tiers. All plans include unlimited signers; higher tiers unlock advanced authentication, API access, and dedicated support." },
      { q: "Can I cancel at any time?", a: "Yes. Monthly plans can be cancelled at any time with no penalties. Annual plans are non-refundable after 30 days but remain active until the period ends." },
    ],
  },
];

